import{o as n,c as s,d as a}from"./app.25ccd784.js";const t='{"title":"系统","description":"","frontmatter":{"title":"系统"},"headers":[{"level":2,"title":"os/exec","slug":"os-exec"},{"level":3,"title":"LookPath","slug":"lookpath"},{"level":3,"title":"Cmd","slug":"cmd"},{"level":3,"title":"Command","slug":"command"},{"level":3,"title":"CommandContext","slug":"commandcontext"},{"level":3,"title":"CombinedOutput","slug":"combinedoutput"},{"level":3,"title":"Output","slug":"output"},{"level":3,"title":"Run","slug":"run"},{"level":3,"title":"Start","slug":"start"},{"level":3,"title":"StderrPipe","slug":"stderrpipe"},{"level":3,"title":"StdinPipe","slug":"stdinpipe"},{"level":3,"title":"StdoutPipe","slug":"stdoutpipe"},{"level":3,"title":"Wait","slug":"wait"},{"level":3,"title":"案例","slug":"案例"}],"relativePath":"docs/golang/base/system.md","lastUpdated":1648110504068}',p={},o=a('<h2 id="os-exec"><a class="header-anchor" href="#os-exec" aria-hidden="true">#</a> os/exec</h2><p>exec 包执行外部命令。它包装了 os.StartProcess 以便更容易的重新映射 stdin 和 stdout，用管道连接 I/O 以及其它的调整。</p><h3 id="lookpath"><a class="header-anchor" href="#lookpath" aria-hidden="true">#</a> LookPath</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">LookPath</span><span class="token punctuation">(</span>file <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>LookPath</code>在环境变量 PATH 中查找文件，如果文件名包含反斜杠则在当前目录中查找。</p><h3 id="cmd"><a class="header-anchor" href="#cmd" aria-hidden="true">#</a> Cmd</h3><div class="language-go"><pre><code><span class="token keyword">type</span> Cmd <span class="token keyword">struct</span> <span class="token punctuation">{</span>\n  Path <span class="token builtin">string</span> <span class="token comment">// 命令路径，该字段不能为空</span>\n  Args <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 命令参数</span>\n  Env <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 进程环境</span>\n  Dir <span class="token builtin">string</span> <span class="token comment">// 工作目录</span>\n  Stdin io<span class="token punctuation">.</span>Reader <span class="token comment">// 标准输入</span>\n  Stdout io<span class="token punctuation">.</span>Writer <span class="token comment">// 标准输出</span>\n  Stderr io<span class="token punctuation">.</span>Writer <span class="token comment">// 标准错误输出</span>\n  ExtraFiles <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>os<span class="token punctuation">.</span>File\n  SysProcAttr <span class="token operator">*</span>syscall<span class="token punctuation">.</span>SysProcAttr\n  Process <span class="token operator">*</span>os<span class="token punctuation">.</span>Process\n  ProcessState <span class="token operator">*</span>os<span class="token punctuation">.</span>ProcessState\n<span class="token punctuation">}</span>\n</code></pre></div><p><code>Cmd</code> 表示一个正在准备中或者执行中的命令。Cmd在调用其 Run Output CombinedOutput 方法之后不能被重复使用。</p><h3 id="command"><a class="header-anchor" href="#command" aria-hidden="true">#</a> Command</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">Command</span><span class="token punctuation">(</span>name <span class="token builtin">string</span><span class="token punctuation">,</span> arg <span class="token operator">...</span><span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>Cmd\n</code></pre></div><p><code>Command</code> 返回一个 *Cmd 结构体，用于使用给出的参数执行 name 指定的程序。返回值只设定了 Path 和 Args 两个参数。</p><h3 id="commandcontext"><a class="header-anchor" href="#commandcontext" aria-hidden="true">#</a> CommandContext</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token function">CommandContext</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> name <span class="token builtin">string</span><span class="token punctuation">,</span> arg <span class="token operator">...</span><span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token operator">*</span>Cmd\n</code></pre></div><p><code>CommandContext</code> 类似于 Command 但是包含了一个 context。context 用来 kill 这个进程，如果 context 结束的比进程早。</p><p>Exmaple</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;context&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n  <span class="token string">&quot;time&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  ctx<span class="token punctuation">,</span> cancel <span class="token operator">:=</span> context<span class="token punctuation">.</span><span class="token function">WithTimeout</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Millisecond<span class="token punctuation">)</span>\n  <span class="token keyword">defer</span> <span class="token function">cancel</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">CommandContext</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;sleep&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;5&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    <span class="token comment">// This will fail after 100 milliseconds. The 5 second sleep will be interrupted.</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="combinedoutput"><a class="header-anchor" href="#combinedoutput" aria-hidden="true">#</a> CombinedOutput</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">CombinedOutput</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">byte</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>CombinedOutput</code> 运行命令，stdout 和 stderr 合并一起返回。</p><p>Example</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;sh&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-c&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;echo stdout; echo 1&gt;&amp;2 stderr&quot;</span><span class="token punctuation">)</span>\n  stdoutStderr<span class="token punctuation">,</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">CombinedOutput</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%s\\n&quot;</span><span class="token punctuation">,</span> stdoutStderr<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="output"><a class="header-anchor" href="#output" aria-hidden="true">#</a> Output</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">Output</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">byte</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>Output</code> 执行命令并返回它的 stdout</p><h3 id="run"><a class="header-anchor" href="#run" aria-hidden="true">#</a> Run</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">error</span>\n</code></pre></div><p><code>Run</code> 执行命令并等待直到执行完成</p><p>Example</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;sleep&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span>\n  log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Running command and waiting for it to finish...&quot;</span><span class="token punctuation">)</span>\n  err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Command finished with error: %v&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="start"><a class="header-anchor" href="#start" aria-hidden="true">#</a> Start</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">error</span>\n</code></pre></div><p><code>Start</code> 执行命令但不会等待命令执行完成。Wait 方法会等待其执行完成并释放其关联的资源</p><p>Example</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\nExample\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;sleep&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;5&quot;</span><span class="token punctuation">)</span>\n  err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Waiting for command to finish...&quot;</span><span class="token punctuation">)</span>\n  err <span class="token operator">=</span> cmd<span class="token punctuation">.</span><span class="token function">Wait</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Command finished with error: %v&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="stderrpipe"><a class="header-anchor" href="#stderrpipe" aria-hidden="true">#</a> StderrPipe</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">StderrPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>io<span class="token punctuation">.</span>ReadCloser<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>StderrPipe</code> 返回一个管道连接该执行命令的 stderr。命令执行完成后 Wait 方法会关闭管道，在 Wait 方法之后从管道中读取内容是不正确的。StderrPipe 不能与 Run 方法一起使用。</p><div class="language-go"><pre><code><span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;io&quot;</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\nExample\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;sh&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-c&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;echo stdout; echo 1&gt;&amp;2 stderr&quot;</span><span class="token punctuation">)</span>\n  stderr<span class="token punctuation">,</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">StderrPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  slurp<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> io<span class="token punctuation">.</span><span class="token function">ReadAll</span><span class="token punctuation">(</span>stderr<span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%s\\n&quot;</span><span class="token punctuation">,</span> slurp<span class="token punctuation">)</span>\n\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Wait</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="stdinpipe"><a class="header-anchor" href="#stdinpipe" aria-hidden="true">#</a> StdinPipe</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">StdinPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>io<span class="token punctuation">.</span>WriteCloser<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>StdinPipe</code> 返回一个管道连接该执行命令的 stdin。命令执行完成后 Wait 方法会关闭管道。</p><div class="language-go"><pre><code><span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;io&quot;</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\nExample\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;cat&quot;</span><span class="token punctuation">)</span>\n  stdin<span class="token punctuation">,</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">StdinPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  <span class="token keyword">go</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">defer</span> stdin<span class="token punctuation">.</span><span class="token function">Close</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    io<span class="token punctuation">.</span><span class="token function">WriteString</span><span class="token punctuation">(</span>stdin<span class="token punctuation">,</span> <span class="token string">&quot;values written to stdin are passed to cmd&#39;s standard input&quot;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n  out<span class="token punctuation">,</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">CombinedOutput</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%s\\n&quot;</span><span class="token punctuation">,</span> out<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="stdoutpipe"><a class="header-anchor" href="#stdoutpipe" aria-hidden="true">#</a> StdoutPipe</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">StdoutPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>io<span class="token punctuation">.</span>ReadCloser<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span>\n</code></pre></div><p><code>StdoutPipe</code> 返回一个管道连接该执行命令的 stdout。命令执行完成后 Wait 方法会关闭管道，在 Wait 方法之后从管道中读取内容是不正确的。StdoutPipe 不能与 Run 方法一起使用。</p><p>Example</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;encoding/json&quot;</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;echo&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-n&quot;</span><span class="token punctuation">,</span> <span class="token string">`{&quot;Name&quot;: &quot;Bob&quot;, &quot;Age&quot;: 32}`</span><span class="token punctuation">)</span>\n  stdout<span class="token punctuation">,</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">StdoutPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">var</span> person <span class="token keyword">struct</span> <span class="token punctuation">{</span>\n    Name <span class="token builtin">string</span>\n    Age  <span class="token builtin">int</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> json<span class="token punctuation">.</span><span class="token function">NewDecoder</span><span class="token punctuation">(</span>stdout<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Decode</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>person<span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">if</span> err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Wait</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%s is %d years old\\n&quot;</span><span class="token punctuation">,</span> person<span class="token punctuation">.</span>Name<span class="token punctuation">,</span> person<span class="token punctuation">.</span>Age<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="wait"><a class="header-anchor" href="#wait" aria-hidden="true">#</a> Wait</h3><div class="language-go"><pre><code><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Cmd<span class="token punctuation">)</span> <span class="token function">Wait</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">error</span>\n</code></pre></div><p><code>Wait</code> 阻塞直到命令执行完成。只能在 Start 方法之后调用。</p><h3 id="案例"><a class="header-anchor" href="#案例" aria-hidden="true">#</a> 案例</h3><p>exmaple1: stdout 和 stderr 分开处理</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;bytes&quot;</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;log&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;ls&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-lah&quot;</span><span class="token punctuation">)</span>\n  <span class="token keyword">var</span> stdout<span class="token punctuation">,</span> stderr bytes<span class="token punctuation">.</span>Buffer\n  cmd<span class="token punctuation">.</span>Stdout <span class="token operator">=</span> <span class="token operator">&amp;</span>stdout\n  cmd<span class="token punctuation">.</span>Stderr <span class="token operator">=</span> <span class="token operator">&amp;</span>stderr\n  err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n    log<span class="token punctuation">.</span><span class="token function">Fatalf</span><span class="token punctuation">(</span><span class="token string">&quot;cmd.Run() failed with %s\\n&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n  outStr<span class="token punctuation">,</span> errStr <span class="token operator">:=</span> stdout<span class="token punctuation">.</span><span class="token function">String</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> stderr<span class="token punctuation">.</span><span class="token function">String</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;out:\\n%s\\nerr:\\n%s\\n&quot;</span><span class="token punctuation">,</span> outStr<span class="token punctuation">,</span> errStr<span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>exmaple2: 如果一个命令需要长时间才能执行完成，在执行过程中 tail -f 输出</p><p><code>test.sh</code></p><div class="language-shell"><pre><code><span class="token shebang important">#!/bin/bash</span>\n\n<span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">seq</span> <span class="token number">1</span> <span class="token number">10</span><span class="token variable">)</span></span>\n<span class="token keyword">do</span>\n    <span class="token builtin class-name">echo</span> TASK<span class="token variable">${i}</span>\n    <span class="token function">sleep</span> <span class="token number">1</span>\n<span class="token keyword">done</span>\n</code></pre></div><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n    <span class="token string">&quot;os/exec&quot;</span>\n    <span class="token string">&quot;io&quot;</span>\n    <span class="token string">&quot;fmt&quot;</span>\n    <span class="token string">&quot;bufio&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    cmd <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;sh&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;test.sh&quot;</span><span class="token punctuation">)</span>\n    stdoutIn<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">StdoutPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    stderrIn<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">StderrPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    err <span class="token operator">:=</span> cmd<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>\n      fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;err&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span>\n    <span class="token punctuation">}</span>\n\n    multi <span class="token operator">:=</span> io<span class="token punctuation">.</span><span class="token function">MultiReader</span><span class="token punctuation">(</span>stdoutIn<span class="token punctuation">,</span> stderrIn<span class="token punctuation">)</span>\n    stdoutLogScan <span class="token operator">:=</span> bufio<span class="token punctuation">.</span><span class="token function">NewScanner</span><span class="token punctuation">(</span>multi<span class="token punctuation">)</span>\n    <span class="token keyword">for</span> stdoutLogScan<span class="token punctuation">.</span><span class="token function">Scan</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>stdoutLogScan<span class="token punctuation">.</span><span class="token function">Text</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>exmaple3: 管道方法实现 <code>ls | wc -l</code></p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;os&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  c1 <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;ls&quot;</span><span class="token punctuation">)</span>\n  c2 <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;wc&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-l&quot;</span><span class="token punctuation">)</span>\n  c2<span class="token punctuation">.</span>Stdin<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">=</span> c1<span class="token punctuation">.</span><span class="token function">StdoutPipe</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  c2<span class="token punctuation">.</span>Stdout <span class="token operator">=</span> os<span class="token punctuation">.</span>Stdout\n  <span class="token boolean">_</span> <span class="token operator">=</span> c2<span class="token punctuation">.</span><span class="token function">Start</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token boolean">_</span> <span class="token operator">=</span> c1<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token boolean">_</span> <span class="token operator">=</span> c2<span class="token punctuation">.</span><span class="token function">Wait</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p>有一种偷巧的办法实现上面的需求</p><div class="language-go"><pre><code><span class="token keyword">package</span> main\n\n<span class="token keyword">import</span> <span class="token punctuation">(</span>\n  <span class="token string">&quot;fmt&quot;</span>\n  <span class="token string">&quot;os&quot;</span>\n  <span class="token string">&quot;os/exec&quot;</span>\n<span class="token punctuation">)</span>\n\n<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  c <span class="token operator">:=</span> exec<span class="token punctuation">.</span><span class="token function">Command</span><span class="token punctuation">(</span><span class="token string">&quot;bash&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-c&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;ls | wc -l&quot;</span><span class="token punctuation">)</span>\n  out<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> c<span class="token punctuation">.</span><span class="token function">Output</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  fmt<span class="token punctuation">.</span><span class="token function">Fprint</span><span class="token punctuation">(</span>os<span class="token punctuation">.</span>Stdout<span class="token punctuation">,</span> <span class="token function">string</span><span class="token punctuation">(</span>out<span class="token punctuation">)</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span>\n</code></pre></div>',61);p.render=function(a,t,p,c,e,u){return n(),s("div",null,[o])};export default p;export{t as __pageData};
